pub export fn Parser_parse_program(arg_self: [*c]Parser) i64 {
    var self = arg_self;
    _ = &self;
    Parser_consume_newlines(self);
    var stmts: ArrayList_Int = ArrayList_Int_init(self.*.allocator);
    _ = &stmts;
    while (Parser_peek(self, @as(i64, @bitCast(@as(c_longlong, @as(c_int, 0))))).tok_type != @as(c_uint, @bitCast(TokenType_EOF))) {
        var stmt: i64 = Parser_parse_statement(self);
        _ = &stmt;
        if (stmt >= @as(i64, @bitCast(@as(c_longlong, @as(c_int, 0))))) {
            ArrayList_Int_push(&stmts, stmt);
        }
        Parser_consume_newlines(self);
    }
    return Parser_st_block(self, stmts);
}
pub export fn Parser_parse_statement(arg_self: [*c]Parser) i64 {
    var self = arg_self;
    _ = &self;
    Parser_consume_newlines(self);
    var tok: Token = Parser_peek(self, @as(i64, @bitCast(@as(c_longlong, @as(c_int, 0)))));
    _ = &tok;
    var is_public: bool = @as(c_int, 0) != 0;
    _ = &is_public;
    if (tok.tok_type == @as(c_uint, @bitCast(TokenType_PUB))) {
        _ = Parser_advance(self);
        is_public = @as(c_int, 1) != 0;
        tok = Parser_peek(self, @as(i64, @bitCast(@as(c_longlong, @as(c_int, 0)))));
    }
    if (tok.tok_type == @as(c_uint, @bitCast(TokenType_LET))) {
        return Parser_parse_var_decl(self, @as(c_int, 0) != 0);
    } else if (tok.tok_type == @as(c_uint, @bitCast(TokenType_VAR))) {
        return Parser_parse_var_decl(self, @as(c_int, 1) != 0);
    } else if (tok.tok_type == @as(c_uint, @bitCast(TokenType_ERROR))) {
        return Parser_parse_error_decl(self);
    } else if (tok.tok_type == @as(c_uint, @bitCast(TokenType_FUNC))) {
        var idx: i64 = Parser_parse_func_decl(self);
        _ = &idx;
        if (is_public) {
            var n: StmtNode = ArrayList_StmtNode_get(self.*.stmt_pool, idx);
            _ = &n;
            n.func_public = @as(c_int, 1) != 0;
            ArrayList_StmtNode_set(self.*.stmt_pool, idx, n);
        }
        return idx;
    } else if (tok.tok_type == @as(c_uint, @bitCast(TokenType_STRUCT))) {
        var idx: i64 = Parser_parse_struct_decl(self);
        _ = &idx;
        if (is_public) {
            var n: StmtNode = ArrayList_StmtNode_get(self.*.stmt_pool, idx);
            _ = &n;
            n.struct_public = @as(c_int, 1) != 0;
            ArrayList_StmtNode_set(self.*.stmt_pool, idx, n);
        }
        return idx;
    } else if (tok.tok_type == @as(c_uint, @bitCast(TokenType_IMPL))) {
        return Parser_parse_impl_block(self);
    } else if (tok.tok_type == @as(c_uint, @bitCast(TokenType_ENUM))) {
        var idx: i64 = Parser_parse_enum_decl(self);
        _ = &idx;
        if (is_public) {
            var n: StmtNode = ArrayList_StmtNode_get(self.*.stmt_pool, idx);
            _ = &n;
            n.enum_public = @as(c_int, 1) != 0;
            ArrayList_StmtNode_set(self.*.stmt_pool, idx, n);
        }
        return idx;
    } else if (tok.tok_type == @as(c_uint, @bitCast(TokenType_MATCH))) {
        return Parser_parse_match_stmt(self);
    } else if (tok.tok_type == @as(c_uint, @bitCast(TokenType_UNSAFE))) {
        return Parser_parse_unsafe_block(self);
    } else if (tok.tok_type == @as(c_uint, @bitCast(TokenType_EXTERN))) {
        return Parser_parse_extern_decl(self);
    } else if (tok.tok_type == @as(c_uint, @bitCast(TokenType_IF))) {
        return Parser_parse_if_stmt(self);
    } else if (tok.tok_type == @as(c_uint, @bitCast(TokenType_WHILE))) {
        return Parser_parse_while_stmt(self);
    } else if (tok.tok_type == @as(c_uint, @bitCast(TokenType_FOR))) {
        return Parser_parse_for_stmt(self);
    } else if (tok.tok_type == @as(c_uint, @bitCast(TokenType_RETURN))) {
        return Parser_parse_return_stmt(self);
    } else if (tok.tok_type == @as(c_uint, @bitCast(TokenType_DEFER))) {
        return Parser_parse_defer_stmt(self);
    } else if (tok.tok_type == @as(c_uint, @bitCast(TokenType_BREAK))) {
        return Parser_parse_break_stmt(self);
    } else if (tok.tok_type == @as(c_uint, @bitCast(TokenType_CONTINUE))) {
        return Parser_parse_continue_stmt(self);
    } else if (tok.tok_type == @as(c_uint, @bitCast(TokenType_USE))) {
        return Parser_parse_import_stmt(self);
    } else if (tok.tok_type == @as(c_uint, @bitCast(TokenType_IMPORT))) {
        return Parser_parse_import_stmt_new(self);
    } else if (tok.tok_type == @as(c_uint, @bitCast(TokenType_CIMPORT))) {
        return Parser_parse_cimport_stmt(self);
    } else if (tok.tok_type == @as(c_uint, @bitCast(TokenType_TRAIT))) {
        var idx: i64 = Parser_parse_trait_decl(self);
        _ = &idx;
        if (is_public) {
            var n: StmtNode = ArrayList_StmtNode_get(self.*.stmt_pool, idx);
            _ = &n;
            n.trait_public = @as(c_int, 1) != 0;
            ArrayList_StmtNode_set(self.*.stmt_pool, idx, n);
        }
        return idx;
    } else {
        return Parser_parse_expr_or_assignment_stmt(self);
    }
    return @import("std").mem.zeroes(i64);
}
pub export fn Parser_parse_type(arg_self: [*c]Parser) [*c]const u8 {
    var self = arg_self;
    _ = &self;
    var base_type: [*c]const u8 = Parser_parse_base_type(self);
    _ = &base_type;
    if (Parser_match_token(self, @as(c_uint, @bitCast(TokenType_NOT)))) {
        var error_set: [*c]const u8 = Parser_parse_type(self);
        _ = &error_set;
        return _kai_str_concat(_kai_str_concat(base_type, "!"), error_set);
    }
    return base_type;
}
pub export fn Parser_parse_base_type(arg_self: [*c]Parser) [*c]const u8 {
    var self = arg_self;
    _ = &self;
    if (Parser_match_token(self, @as(c_uint, @bitCast(TokenType_OWN)))) {
        var inner: [*c]const u8 = Parser_parse_type(self);
        _ = &inner;
        return _kai_str_concat("own ", inner);
    } else if (Parser_match_token(self, @as(c_uint, @bitCast(TokenType_QUESTION)))) {
        return _kai_str_concat("?", Parser_parse_type(self));
    } else if (Parser_match_token(self, @as(c_uint, @bitCast(TokenType_AMP)))) {
        var is_mut: bool = @as(c_int, 0) != 0;
        _ = &is_mut;
        if (Parser_match_token(self, @as(c_uint, @bitCast(TokenType_MUT)))) {
            is_mut = @as(c_int, 1) != 0;
        }
        var inner: [*c]const u8 = Parser_parse_type(self);
        _ = &inner;
        if (is_mut) {
            return _kai_str_concat("*mut ", inner);
        }
        return _kai_str_concat("*", inner);
    } else if (Parser_match_token(self, @as(c_uint, @bitCast(TokenType_MUL)))) {
        var is_mut: bool = @as(c_int, 0) != 0;
        _ = &is_mut;
        if (Parser_match_token(self, @as(c_uint, @bitCast(TokenType_MUT)))) {
            is_mut = @as(c_int, 1) != 0;
        }
        var inner: [*c]const u8 = Parser_parse_type(self);
        _ = &inner;
        if (is_mut) {
            return _kai_str_concat("*mut ", inner);
        }
        return _kai_str_concat("*", inner);
    } else if (Parser_match_token(self, @as(c_uint, @bitCast(TokenType_LBRACKET)))) {
        _ = Parser_expect(self, @as(c_uint, @bitCast(TokenType_RBRACKET)));
        return _kai_str_concat("[]", Parser_parse_type(self));
    } else if (Parser_match_token(self, @as(c_uint, @bitCast(TokenType_LPAREN)))) {
        var types: ArrayList_Str = ArrayList_Str_init(self.*.allocator);
        _ = &types;
        if (Parser_peek(self, @as(i64, @bitCast(@as(c_longlong, @as(c_int, 0))))).tok_type != @as(c_uint, @bitCast(TokenType_RPAREN))) {
            var done: bool = @as(c_int, 0) != 0;
            _ = &done;
            while (!done) {
                ArrayList_Str_push(&types, Parser_parse_type(self));
                if (!Parser_match_token(self, @as(c_uint, @bitCast(TokenType_COMMA)))) {
                    done = @as(c_int, 1) != 0;
                }
            }
        }
        _ = Parser_expect(self, @as(c_uint, @bitCast(TokenType_RPAREN)));
        return _kai_str_concat(_kai_str_concat("(", str_array_join(types, ", ")), ")");
    } else {
        var name: [*c]const u8 = tv_get_str(Parser_expect(self, @as(c_uint, @bitCast(TokenType_IDENTIFIER))).value);
        _ = &name;
        if (Parser_peek(self, @as(i64, @bitCast(@as(c_longlong, @as(c_int, 0))))).tok_type == @as(c_uint, @bitCast(TokenType_LT))) {
            _ = Parser_advance(self);
            var type_args: ArrayList_Str = ArrayList_Str_init(self.*.allocator);
            _ = &type_args;
            var done: bool = @as(c_int, 0) != 0;
