                    ArrayList_Str_push(&bindings, tv_get_str(Parser_expect(self, @as(c_uint, @bitCast(TokenType_IDENTIFIER))).value));
                    if (!Parser_match_token(self, @as(c_uint, @bitCast(TokenType_COMMA)))) {
                        done = @as(c_int, 1) != 0;
                    }
                }
            }
            _ = Parser_expect(self, @as(c_uint, @bitCast(TokenType_RPAREN)));
        }
        var node: PatternNode = new_pattern_node(@as(c_uint, @bitCast(PatternKind_pk_variant)));
        _ = &node;
        node.variant_name = v_name;
        node.bindings = bindings;
        return Parser_add_pattern(self, node);
    } else if (tok.tok_type == @as(c_uint, @bitCast(TokenType_ELSE))) {
        _ = Parser_advance(self);
        return Parser_add_pattern(self, new_pattern_node(@as(c_uint, @bitCast(PatternKind_pk_else))));
    } else if (((((tok.tok_type == @as(c_uint, @bitCast(TokenType_INT_LIT))) or (tok.tok_type == @as(c_uint, @bitCast(TokenType_FLOAT_LIT)))) or (tok.tok_type == @as(c_uint, @bitCast(TokenType_BOOL_LIT)))) or (tok.tok_type == @as(c_uint, @bitCast(TokenType_STRING_LIT)))) or (tok.tok_type == @as(c_uint, @bitCast(TokenType_CHAR_LIT)))) {
        _ = Parser_advance(self);
        var node: PatternNode = new_pattern_node(@as(c_uint, @bitCast(PatternKind_pk_literal)));
        _ = &node;
        node.lit_value = tok.value;
        return Parser_add_pattern(self, node);
    } else {
        {
            _ = printf("error[E0101]: unexpected token in pattern at line %lld, column %lld\n", tok.line, tok.column);
