pub export fn TypeChecker_expr_is_mutable(arg_self: [*c]TypeChecker, arg_expr_idx: i64) bool {
    var self = arg_self;
    _ = &self;
    var expr_idx = arg_expr_idx;
    _ = &expr_idx;
    if (expr_idx < @as(i64, @bitCast(@as(c_longlong, @as(c_int, 0))))) {
        return @as(c_int, 0) != 0;
    }
    var expr: ExprNode = ArrayList_ExprNode_get(self.*.expr_pool, expr_idx);
    _ = &expr;
    if (expr.kind == @as(c_uint, @bitCast(ExprKind_ek_identifier))) {
        var table: SymbolTable = ArrayList_SymbolTable_get(&self.*.symbol_tables, self.*.current_table_idx);
        _ = &table;
        var sym: Symbol = SymbolTable_lookup_symbol(&table, expr.ident_name, &self.*.symbol_tables);
        _ = &sym;
        if (strlen(sym.name) > @as(c_ulong, @bitCast(@as(c_long, @as(c_int, 0))))) {
            return sym.is_mutable;
        }
    }
    if (expr.kind == @as(c_uint, @bitCast(ExprKind_ek_field_access))) {
        return TypeChecker_expr_is_mutable(self, expr.field_expr);
    }
    if (expr.kind == @as(c_uint, @bitCast(ExprKind_ek_deref))) {
        return @as(c_int, 1) != 0;
    }
    return @as(c_int, 0) != 0;
}
pub export fn TypeChecker_is_enum_or_error_type(arg_self: [*c]TypeChecker, arg_name: [*c]const u8) bool {
