            .description = "A function was called but not declared or imported in the current scope.",
            .fix = "Declare the function with 'fn', declare it as 'extern fn', or import it from the appropriate module. Check the spelling.",
        };
    }
    if (strcmp(code, "E0021") == @as(c_int, 0)) {
        return ErrorInfo{
            .code = code,
            .title = "Undefined struct",
            .description = "A struct type was used but not declared in the current compilation unit.",
            .fix = "Define the struct with 'struct', import it, or check the spelling of the struct name.",
        };
    }
    if (strcmp(code, "E0022") == @as(c_int, 0)) {
        return ErrorInfo{
            .code = code,
            .title = "Undefined method",
            .description = "A method was called on a type that does not have that method in any 'impl' block.",
            .fix = "Add an 'impl' block with the method, check the spelling of the method name, or check the receiver type.",
        };
    }
    if (strcmp(code, "E0100") == @as(c_int, 0)) {
        return ErrorInfo{
            .code = code,
            .title = "Lexer error",
            .description = "The lexer encountered an unexpected character or syntax that could not be tokenized.",
            .fix = "Check for unexpected characters, unclosed strings, or invalid syntax near the reported position.",
        };
    }
    if (strcmp(code, "E0101") == @as(c_int, 0)) {
        return ErrorInfo{
            .code = code,
            .title = "Parser error",
            .description = "The parser encountered a token that does not match the expected grammar rule.",
            .fix = "Check the syntax near the reported position. Common causes: missing semicolons, unmatched brackets, or incorrect keyword usage.",
        };
    }
    return ErrorInfo{
        .code = code,
        .title = "Unknown error code",
        .description = "No additional information is available for this error code.",
        .fix = "Refer to the Kai language documentation for more information.",
    };
}
pub export fn find_last(arg_path: [*c]const u8, arg_c: u8) i64 {
