}
pub export fn str_replace(arg_s: [*c]const u8, arg_old: [*c]const u8, arg_new_val: [*c]const u8) [*c]const u8 {
    var s = arg_s;
    _ = &s;
    var old = arg_old;
    _ = &old;
    var new_val = arg_new_val;
    _ = &new_val;
    var s_len: i64 = @as(i64, @bitCast(@as(c_ulonglong, strlen(s))));
    _ = &s_len;
    var old_len: i64 = @as(i64, @bitCast(@as(c_ulonglong, strlen(old))));
    _ = &old_len;
    if (old_len == @as(i64, @bitCast(@as(c_longlong, @as(c_int, 0))))) {
        return s;
    }
    var result: [*c]const u8 = "";
    _ = &result;
    var i: i64 = 0;
    _ = &i;
    while (i < s_len) {
        var j: i64 = 0;
        _ = &j;
        var matched: bool = @as(c_int, 1) != 0;
        _ = &matched;
        while (j < old_len) {
            {
                if (@as(c_int, @bitCast(@as(c_uint, (blk: {
                    const tmp = i + j;
                    if (tmp >= 0) break :blk s + @as(usize, @intCast(tmp)) else break :blk s - ~@as(usize, @bitCast(@as(isize, @intCast(tmp)) +% -1));
                }).*))) != @as(c_int, @bitCast(@as(c_uint, (blk: {
                    const tmp = j;
                    if (tmp >= 0) break :blk old + @as(usize, @intCast(tmp)) else break :blk old - ~@as(usize, @bitCast(@as(isize, @intCast(tmp)) +% -1));
                }).*)))) {
                    matched = @as(c_int, 0) != 0;
                    break;
                }
            }
            j = j + @as(i64, @bitCast(@as(c_longlong, @as(c_int, 1))));
        }
