pub export fn main(arg_argc: c_int, arg_argv: [*c][*c]u8) c_int {
    var argc = arg_argc;
    _ = &argc;
    var argv = arg_argv;
    _ = &argv;
    if (argc < @as(c_int, 2)) {
        _ = printf("Usage: kai <command> [options]\n");
        _ = printf("Commands:\n");
        _ = printf("  init [path]     Create a new Kai project\n");
        _ = printf("  check <file>    Type-check only (no code generation)\n");
        _ = printf("  run <file>      Compile and run a .kai file\n");
        _ = printf("  <file>          Compile and run (shorthand)\n");
        _ = printf("  patch <file>    Apply an operation-based edit\n");
        _ = printf("  explain <code>  Explain an error code\n");
        _ = printf("  skills          List available agent skills\n");
        _ = printf("  fix <file>      Auto-fix diagnostics (--plan|--patch|--apply)\n");
        _ = printf("  graph <file>    Export or query the AST graph\n");
        _ = printf("Flags:\n");
        _ = printf("  --json          Output diagnostics in JSON format\n");
        _ = printf("  -o <file>       Specify output binary name\n");
        _ = printf("  -c              Emit C code only (no linking)\n");
        _ = printf("  -O0|-O1|-O2|-O3|-Os  Optimization level (default: -O2)\n");
        return 1;
    }
