        }
        _ = printf("Usage: kai skills get <topic>\n");
        return 1;
    }
    var is_init: bool = @as(c_int, 0) != 0;
    _ = &is_init;
    {
        if (strcmp(first_arg, "init") == @as(c_int, 0)) {
            is_init = @as(c_int, 1) != 0;
        }
    }
    if (is_init) {
        var project_path: [*c]const u8 = ".";
