                        template = @as([*c]const u8, @ptrCast(@alignCast((blk: {
                            const tmp = i;
                            if (tmp >= 0) break :blk argv + @as(usize, @intCast(tmp)) else break :blk argv - ~@as(usize, @bitCast(@as(isize, @intCast(tmp)) +% -1));
                        }).*)));
