    }
    var is_patch: bool = @as(c_int, 0) != 0;
    _ = &is_patch;
    {
        if (strcmp(first_arg, "patch") == @as(c_int, 0)) {
            is_patch = @as(c_int, 1) != 0;
        }
    }
    if (is_patch) {
